import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.within;

import org.junit.jupiter.api.Test;

class StableQuadraticTest {
    @Test
    void returnsNearZeroRootForOrdinaryInputs() {
        assertThat(StableQuadratic.nearZeroRoot(5.0, 6.0))
            .isCloseTo(-2.0, within(2e-12));
    }

    @Test
    void retainsRootWhenDirectSubtractionCancels() {
        assertThat(StableQuadratic.nearZeroRoot(1e16, 1.0))
            .isCloseTo(-1e-16, within(1e-28));
    }

    @Test
    void remainsAccurateForAnotherSeparatedRootPair() {
        assertThat(StableQuadratic.nearZeroRoot(1e12, 3.0))
            .isCloseTo(-3e-12, within(3e-24));
    }
}

