import math

from relative_log_change import relative_log_change


def test_zero_uses_continuous_limit():
    assert relative_log_change(0.0) == 1.0


def test_tiny_positive_change_retains_information():
    assert math.isclose(relative_log_change(1e-16), 1.0, rel_tol=0.0, abs_tol=1e-15)


def test_small_negative_change_is_accurate():
    expected = 1.0000000050000001
    assert math.isclose(relative_log_change(-1e-8), expected, rel_tol=0.0, abs_tol=1e-15)

