import math

from root_difference import root_difference


def test_unit_value():
    assert math.isclose(root_difference(1.0), math.sqrt(2.0) - 1.0, rel_tol=0.0, abs_tol=1e-15)


def test_large_finite_value_keeps_small_difference():
    assert math.isclose(root_difference(1e16), 5e-9, rel_tol=1e-8, abs_tol=0.0)


def test_very_large_finite_value_does_not_collapse_to_zero():
    result = root_difference(1e30)
    assert result > 0.0
    assert math.isclose(result, 5e-16, rel_tol=1e-8, abs_tol=0.0)
